def cargar_clubs():
    """Devuelve [{'id', 'nombre'}] del bloque de clubs."""
    salida = []
    for linea in _CLUBS.strip().splitlines():
        tokens = linea.split()
        if len(tokens) < 2:
            continue
        salida.append({"id": tokens[0], "nombre": " ".join(tokens[1:]).strip()})
    return salida


def cargar_equipos():
    """Devuelve [{'id', 'club_id', 'nombre', 'categoria_uuid'}] del bloque de equipos.

    Se parsea por tokens: id (UUID) | club_id (UUID o NULL) | nombre... | categoria (UUID).
    """
    salida = []
    for linea in _EQUIPOS.strip().splitlines():
        tokens = linea.split()
        if len(tokens) < 4:
            continue
        eid = tokens[0]
        club = tokens[1]
        cat = tokens[-1]
        nombre = " ".join(tokens[2:-1]).strip()
        salida.append(
            {
                "id": eid,
                "club_id": None if club.upper() == "NULL" else club,
                "nombre": nombre,
                "categoria_uuid": cat,
            }
        )
    return salida
